    Args:
        n: The number of squares in the Blokus pieces.

    Returns:
        A set of frozensets, where each frozenset represents a unique Blokus piece.
        Each element in the frozenset is a tuple (x, y) representing the coordinates
        of a square in the piece.
    """

    if n <= 0:
        return set()

    if n == 1:
        return {frozenset({(0, 0)})}

    pieces = set()

    def normalize(piece):
        """Normalizes a piece by translating it to the origin."""
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        return frozenset((x - min_x, y - min_y) for x, y in piece)

    def rotate(piece):
        """Rotates a piece 90 degrees clockwise."""
        return frozenset((y, -x) for x, y in piece)

    def flip(piece):
        """Flips a piece horizontally."""
        return frozenset((-x, y) for x, y in piece)

    def all_transformations(piece):
        """Generates all possible transformations of a piece (rotations and flips)."""
        transformations = set()
        for _ in range(4):
            piece = rotate(piece)
            transformations.add(normalize(piece))
            transformations.add(normalize(flip(piece)))
        return transformations

