        return {frozenset({(0, 0)})}

    polyominoes = set()

    def normalize(polyomino):
        """
        Normalizes a polyomino by translating it to the origin.
        """
        min_x = min(x for x, y in polyomino)
        min_y = min(y for x, y in polyomino)
        return frozenset((x - min_x, y - min_y) for x, y in polyomino)

    def rotate(polyomino):
        """
        Rotates a polyomino 90 degrees clockwise.
        """
        return frozenset((y, -x) for x, y in polyomino)

    def reflect(polyomino):
        """
        Reflects a polyomino across the x-axis.
        """
        return frozenset((x, -y) for x, y in polyomino)

    def canonicalize(polyomino):
        """
        Returns the canonical representation of a polyomino by applying
        rotations and reflections and choosing the lexicographically smallest.
        """
        normalized = normalize(polyomino)
        variants = {normalized}
        for _ in range(3):
            normalized = rotate(normalized)
            variants.add(normalized)
        reflected = reflect(normalized)
        variants.add(reflected)
        for _ in range(3):
            reflected = rotate(reflected)
            variants.add(reflected)
        return min(variants)

    def grow_polyomino(polyomino):
        """
        Grows a polyomino by adding a square to each of its neighbors.
        """
        new_polyominoes = set()
        for x, y in polyomino:
            neighbors = [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
            for nx, ny in neighbors:
                if (nx, ny) not in polyomino:
                    new_polyomino = polyomino | {(nx, ny)}
                    new_polyominoes.add(new_polyomino)
        return new_polyominoes

    previous_polyominoes = generate_polyominoes(n - 1)

    for polyomino in previous_polyominoes:
        for new_polyomino in grow_polyomino(polyomino):
            polyominoes.add(canonicalize(new_polyomino))

    return polyominoes

if __name__ == '__main__':
